const allRows = $('Query Database').all();

const funnelByOrigin = allRows.map(row => {
  const etapas = row.json.etapas || {};
  return {
    origin: row.json.origen === 'RECOMENDACION' ? 'Recomendación' : 'Orgánico',
    nuevos: etapas.Nuevos || 0,
    nutriendo: etapas.Nutriendo || 0,
    conversion: etapas.Conversión || 0,
    tasa_conversion: etapas.Nuevos > 0 ? Math.round((etapas.Conversión || 0) / etapas.Nuevos * 100) : 0
  };
});

return [{
  json: {
    items: funnelByOrigin
  }
}];
